
from sqlalchemy import Column, Index, Table, ForeignKey
from sqlalchemy.orm import relationship
from sqlalchemy.sql.sqltypes import *
from sqlalchemy.orm import declarative_base
from sqlalchemy.ext.associationproxy import association_proxy

Base = declarative_base()
metadata = Base.metadata


class AdjustableDate(Base):
    """
    A class for defining a date that shall be subject to adjustment if it would otherwise fall on a day that is not a business day in the specified business centers, together with the convention for adjusting the date.
    """
    __tablename__ = 'AdjustableDate'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    unadjustedDate = Column(Date())
    adjustedDate = Column(Date())
    dateAdjustments_id = Column(Integer(), ForeignKey('BusinessDayAdjustments.id'))
    dateAdjustments = relationship("BusinessDayAdjustments", uselist=False, foreign_keys=[dateAdjustments_id])
    dateAdjustmentsReference_id = Column(Integer(), ForeignKey('BusinessDayAdjustments.id'))
    dateAdjustmentsReference = relationship("BusinessDayAdjustments", uselist=False, foreign_keys=[dateAdjustmentsReference_id])
    

    def __repr__(self):
        return f"AdjustableDate(id={self.id},unadjustedDate={self.unadjustedDate},adjustedDate={self.adjustedDate},dateAdjustments_id={self.dateAdjustments_id},dateAdjustmentsReference_id={self.dateAdjustmentsReference_id},)"



    


class AdjustableDates(Base):
    """
    A class for defining a series of dates that shall be subject to adjustment if they would otherwise fall on a day that is not a business day in the specified business centers, together with the convention for adjusting the dates.
    """
    __tablename__ = 'AdjustableDates'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    PricingDates_id = Column(Integer(), ForeignKey('PricingDates.id'))
    dateAdjustments_id = Column(Integer(), ForeignKey('BusinessDayAdjustments.id'))
    dateAdjustments = relationship("BusinessDayAdjustments", uselist=False, foreign_keys=[dateAdjustments_id])
    
    
    unadjustedDate_rel = relationship( "AdjustableDatesUnadjustedDate" )
    unadjustedDate = association_proxy("unadjustedDate_rel", "unadjustedDate",
                                  creator=lambda x_: AdjustableDatesUnadjustedDate(unadjustedDate=x_))
    
    
    adjustedDate_rel = relationship( "AdjustableDatesAdjustedDate" )
    adjustedDate = association_proxy("adjustedDate_rel", "adjustedDate",
                                  creator=lambda x_: AdjustableDatesAdjustedDate(adjustedDate=x_))
    

    def __repr__(self):
        return f"AdjustableDates(id={self.id},PricingDates_id={self.PricingDates_id},dateAdjustments_id={self.dateAdjustments_id},)"



    


class AdjustableOrAdjustedDate(Base):
    """
    A class for defining a date that shall be subject to adjustment if it would otherwise fall on a day that is not a business day in the specified business centers, together with the convention for adjusting the date.
    """
    __tablename__ = 'AdjustableOrAdjustedDate'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    unadjustedDate = Column(Date())
    adjustedDate = Column(Date())
    dateAdjustments_id = Column(Integer(), ForeignKey('BusinessDayAdjustments.id'))
    dateAdjustments = relationship("BusinessDayAdjustments", uselist=False, foreign_keys=[dateAdjustments_id])
    

    def __repr__(self):
        return f"AdjustableOrAdjustedDate(id={self.id},unadjustedDate={self.unadjustedDate},adjustedDate={self.adjustedDate},dateAdjustments_id={self.dateAdjustments_id},)"



    


class AdjustableOrAdjustedOrRelativeDate(Base):
    """
    This Rosetta class specifies the date as either an unadjusted, adjusted or relative date. It supplements the features of the AdjustableOrAdjustedDate to support the credit default swap option premium, which uses the relative date construct.
    """
    __tablename__ = 'AdjustableOrAdjustedOrRelativeDate'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    unadjustedDate = Column(Date())
    adjustedDate = Column(Date())
    dateAdjustments_id = Column(Integer(), ForeignKey('BusinessDayAdjustments.id'))
    dateAdjustments = relationship("BusinessDayAdjustments", uselist=False, foreign_keys=[dateAdjustments_id])
    relativeDate_id = Column(Integer(), ForeignKey('RelativeDateOffset.id'))
    relativeDate = relationship("RelativeDateOffset", uselist=False, foreign_keys=[relativeDate_id])
    

    def __repr__(self):
        return f"AdjustableOrAdjustedOrRelativeDate(id={self.id},unadjustedDate={self.unadjustedDate},adjustedDate={self.adjustedDate},dateAdjustments_id={self.dateAdjustments_id},relativeDate_id={self.relativeDate_id},)"



    


class AdjustableOrRelativeDate(Base):
    """
    A class giving the choice between defining a date as an explicit date together with applicable adjustments or as relative to some other (anchor) date.
    """
    __tablename__ = 'AdjustableOrRelativeDate'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    adjustableDate_id = Column(Integer(), ForeignKey('AdjustableDate.id'))
    adjustableDate = relationship("AdjustableDate", uselist=False, foreign_keys=[adjustableDate_id])
    relativeDate_id = Column(Integer(), ForeignKey('AdjustedRelativeDateOffset.id'))
    relativeDate = relationship("AdjustedRelativeDateOffset", uselist=False, foreign_keys=[relativeDate_id])
    

    def __repr__(self):
        return f"AdjustableOrRelativeDate(id={self.id},adjustableDate_id={self.adjustableDate_id},relativeDate_id={self.relativeDate_id},)"



    


class AdjustableOrRelativeDates(Base):
    """
    A class giving the choice between defining a series of dates as an explicit list of dates together with applicable adjustments or as relative to some other series of (anchor) dates.
    """
    __tablename__ = 'AdjustableOrRelativeDates'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
