    businessCenter_rel = relationship( "CalculationFrequencyBusinessCenter" )
    businessCenter = association_proxy("businessCenter_rel", "businessCenter",
                                  creator=lambda x_: CalculationFrequencyBusinessCenter(businessCenter=x_))
    

    def __repr__(self):
        return f"CalculationFrequency(id={self.id},monthOfYear={self.monthOfYear},dayOfMonth={self.dayOfMonth},dayOfWeek={self.dayOfWeek},weekOfMonth={self.weekOfMonth},offsetDays={self.offsetDays},period_id={self.period_id},dateLocation_id={self.dateLocation_id},)"



    


