    previousWorkflowStep_id = Column(Integer(), ForeignKey('WorkflowStep.id'))
    previousWorkflowStep = relationship("WorkflowStep", uselist=False, foreign_keys=[previousWorkflowStep_id])
    nextEvent_id = Column(Integer(), ForeignKey('EventInstruction.id'))
    nextEvent = relationship("EventInstruction", uselist=False, foreign_keys=[nextEvent_id])
    messageInformation_id = Column(Integer(), ForeignKey('MessageInformation.id'))
    messageInformation = relationship("MessageInformation", uselist=False, foreign_keys=[messageInformation_id])
    lineage_id = Column(Integer(), ForeignKey('Lineage.id'))
