    creditLimitInformation = relationship("CreditLimitInformation", uselist=False, foreign_keys=[creditLimitInformation_id])
    workflowState_id = Column(Integer(), ForeignKey('WorkflowState.id'))
    workflowState = relationship("WorkflowState", uselist=False, foreign_keys=[workflowState_id])
    
    
    # One-To-Many: OneToAnyMapping(source_class='WorkflowStep', source_slot='approval', mapping_type=None, target_class='WorkflowStepApproval', target_slot='WorkflowStep_id', join_class=None, uses_join_table=None, multivalued=False)
