class Resource(Base):
    """
    Describes the resource that contains the media representation of a business event (i.e used for stating the Publicly Available Information). For example, can describe a file or a URL that represents the event. This type is an extended version of a type defined by RIXML (www.rixml.org).  Rosetta restricts the FpML implementation by not providing the ability to associated a document in hexadecimalBinary or base64Binary until such time that actual use cases will come up.
    """
    __tablename__ = 'Resource'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    resourceId = Column(Text(), nullable=False )
    resourceType = Column(Enum('Confirmation', 'SupplementalMaterialEconomicTerms', 'TermSheet', name='ResourceTypeEnum'))
    language = Column(Text())
    sizeInBytes = Column(Numeric())
    mimeType = Column(Text())
    name = Column(Text())
    comments = Column(Text())
    string = Column(Text())
    url = Column(Text())
    CreditEvent_id = Column(Integer(), ForeignKey('CreditEvent.id'))
    LegalAgreement_id = Column(Integer(), ForeignKey('LegalAgreement.id'))
    LegalAgreementBase_id = Column(Integer(), ForeignKey('LegalAgreementBase.id'))
    length_id = Column(Integer(), ForeignKey('ResourceLength.id'))
    length = relationship("ResourceLength", uselist=False, foreign_keys=[length_id])
    

    def __repr__(self):
        return f"Resource(id={self.id},resourceId={self.resourceId},resourceType={self.resourceType},language={self.language},sizeInBytes={self.sizeInBytes},mimeType={self.mimeType},name={self.name},comments={self.comments},string={self.string},url={self.url},CreditEvent_id={self.CreditEvent_id},LegalAgreement_id={self.LegalAgreement_id},LegalAgreementBase_id={self.LegalAgreementBase_id},length_id={self.length_id},)"



    


