class PriceQuantity(Base):
    """
    Defines a settlement as an exchange between two parties of a specified quantity of an asset (the quantity) against a specified quantity of another asset (the price). The settlement is optional and can be either cash or physical. The quantity can additionally be specified in terms of one or more currency amounts. In the case of non-cash products, the settlement of the price/quantity would not be specified here and instead would be delegated to the product mechanics, as parameterised by the price/quantity values.
    """
    __tablename__ = 'PriceQuantity'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    ExecutionInstruction_id = Column(Integer(), ForeignKey('ExecutionInstruction.id'))
    QuantityChangeInstruction_id = Column(Integer(), ForeignKey('QuantityChangeInstruction.id'))
    IndexTransitionInstruction_id = Column(Integer(), ForeignKey('IndexTransitionInstruction.id'))
    CollateralPosition_id = Column(Integer(), ForeignKey('CollateralPosition.id'))
    PositionBase_id = Column(Integer(), ForeignKey('PositionBase.id'))
    Position_id = Column(Integer(), ForeignKey('Position.id'))
    TradeLot_id = Column(Integer(), ForeignKey('TradeLot.id'))
    observable_id = Column(Integer(), ForeignKey('Observable.id'))
    observable = relationship("Observable", uselist=False, foreign_keys=[observable_id])
    effectiveDate_id = Column(Integer(), ForeignKey('AdjustableOrRelativeDate.id'))
    effectiveDate = relationship("AdjustableOrRelativeDate", uselist=False, foreign_keys=[effectiveDate_id])
    
    
    # ManyToMany
    price = relationship( "PriceSchedule", secondary="PriceQuantity_price")
    
    
    # ManyToMany
    quantity = relationship( "NonNegativeQuantitySchedule", secondary="PriceQuantity_quantity")
    

    def __repr__(self):
        return f"PriceQuantity(id={self.id},ExecutionInstruction_id={self.ExecutionInstruction_id},QuantityChangeInstruction_id={self.QuantityChangeInstruction_id},IndexTransitionInstruction_id={self.IndexTransitionInstruction_id},CollateralPosition_id={self.CollateralPosition_id},PositionBase_id={self.PositionBase_id},Position_id={self.Position_id},TradeLot_id={self.TradeLot_id},observable_id={self.observable_id},effectiveDate_id={self.effectiveDate_id},)"



    


class PriceComposite(Base):
    """
    Defines the inputs required to calculate a price as a simple composite of 2 other values. The inputs consist of 2 numbers and a simple arithmetic operator. This generic data type applies to a variety of use cases where a price is obtained by simple composition, e.g. dirty = clean + accrued (Bond), forward rate = spot rate + forward point (FX) etc.
    """
    __tablename__ = 'PriceComposite'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    baseValue = Column(Numeric(), nullable=False )
    operand = Column(Numeric(), nullable=False )
    arithmeticOperator = Column(Enum('Add', 'Subtract', 'Multiply', 'Divide', 'Max', 'Min', name='ArithmeticOperationEnum'), nullable=False )
    operandType = Column(Enum('AccruedInterest', 'Commission', 'ForwardPoint', name='PriceOperandEnum'))
    

    def __repr__(self):
        return f"PriceComposite(id={self.id},baseValue={self.baseValue},operand={self.operand},arithmeticOperator={self.arithmeticOperator},operandType={self.operandType},)"



    


class InformationSource(Base):
    """
    A class defining the source for a piece of information (e.g. a rate fix or an FX fixing). The attribute names have been adjusted from FpML to address the fact that the information is not limited to rates.
    """
    __tablename__ = 'InformationSource'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    sourceProvider = Column(Enum('AssocBanksSingapore', 'BancoCentralChile', 'BankOfCanada', 'BankOfEngland', 'BankOfJapan', 'Bloomberg', 'EuroCentralBank', 'FederalReserve', 'FHLBSF', 'ICESWAP', 'ISDA', 'Refinitiv', 'ReserveBankAustralia', 'ReserveBankNewZealand', 'Reuters', 'SAFEX', 'Telerate', 'TOKYOSWAP', name='InformationProviderEnum'), nullable=False )
    sourcePage = Column(Text())
    sourcePageHeading = Column(Text())
    

    def __repr__(self):
        return f"InformationSource(id={self.id},sourceProvider={self.sourceProvider},sourcePage={self.sourcePage},sourcePageHeading={self.sourcePageHeading},)"



    


class QuotedCurrencyPair(Base):
    """
    A class that describes the composition of a rate that has been quoted or is to be quoted. This includes the two currencies and the quotation relationship between the two currencies and is used as a building block throughout the FX specification.
    """
    __tablename__ = 'QuotedCurrencyPair'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    currency1 = Column(Text(), nullable=False )
    currency2 = Column(Text(), nullable=False )
    quoteBasis = Column(Enum('Currency1PerCurrency2', 'Currency2PerCurrency1', name='QuoteBasisEnum'), nullable=False )
    

    def __repr__(self):
        return f"QuotedCurrencyPair(id={self.id},currency1={self.currency1},currency2={self.currency2},quoteBasis={self.quoteBasis},)"



    


