class TransactedPrice(Base):
    """
     A class to represent the transacted price attributes that are positioned as part of the FpML FeeLeg.
    """
    __tablename__ = 'TransactedPrice'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    marketFixedRate = Column(Numeric())
    initialPoints = Column(Numeric())
    marketPrice = Column(Numeric())
    quotationStyle = Column(Enum('PointsUpFront', 'TradedSpread', 'Price', name='QuotationStyleEnum'))
    

    def __repr__(self):
        return f"TransactedPrice(id={self.id},marketFixedRate={self.marketFixedRate},initialPoints={self.initialPoints},marketPrice={self.marketPrice},quotationStyle={self.quotationStyle},)"



    


class ReferenceSwapCurve(Base):
    """
    A complex type used to specify the option and convertible bond option strike when expressed in reference to a swap curve.
    """
    __tablename__ = 'ReferenceSwapCurve'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    swapUnwindValue_id = Column(Integer(), ForeignKey('SwapCurveValuation.id'), nullable=False )
    swapUnwindValue = relationship("SwapCurveValuation", uselist=False, foreign_keys=[swapUnwindValue_id])
    makeWholeAmount_id = Column(Integer(), ForeignKey('MakeWholeAmount.id'))
    makeWholeAmount = relationship("MakeWholeAmount", uselist=False, foreign_keys=[makeWholeAmount_id])
    

    def __repr__(self):
        return f"ReferenceSwapCurve(id={self.id},swapUnwindValue_id={self.swapUnwindValue_id},makeWholeAmount_id={self.makeWholeAmount_id},)"



    


class SwapCurveValuation(Base):
    """
    A class to specify a valuation swap curve, which is used as part of the strike construct for the bond and convertible bond options.
    """
