class ValuationDates(Base):
    """
    Defines how and when a performance type option or performance type swap is to be valued, including initial, interim and final valuation dates.
    """
    __tablename__ = 'ValuationDates'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    initialValuationDate_id = Column(Integer(), ForeignKey('PerformanceValuationDates.id'))
    initialValuationDate = relationship("PerformanceValuationDates", uselist=False, foreign_keys=[initialValuationDate_id])
    interimValuationDate_id = Column(Integer(), ForeignKey('PerformanceValuationDates.id'))
    interimValuationDate = relationship("PerformanceValuationDates", uselist=False, foreign_keys=[interimValuationDate_id])
    finalValuationDate_id = Column(Integer(), ForeignKey('PerformanceValuationDates.id'), nullable=False )
    finalValuationDate = relationship("PerformanceValuationDates", uselist=False, foreign_keys=[finalValuationDate_id])
    

    def __repr__(self):
        return f"ValuationDates(id={self.id},initialValuationDate_id={self.initialValuationDate_id},interimValuationDate_id={self.interimValuationDate_id},finalValuationDate_id={self.finalValuationDate_id},)"



    


class PerformanceValuationDates(Base):
    """
    Defines how and when a performance type option or performance type swap is to be valued.
    """
    __tablename__ = 'PerformanceValuationDates'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    determinationMethod = Column(Enum('AgreedInitialPrice', 'AsSpecifiedInMasterConfirmation', 'CalculationAgent', 'ClosingPrice', 'DividendCurrency', 'ExpiringContractLevel', 'HedgeExecution', 'IssuerPaymentCurrency', 'NAV', 'OpenPrice', 'OSPPrice', 'SettlementCurrency', 'StrikeDateDetermination', 'TWAPPrice', 'TWAPVE', 'TWAPVEExcludingClose', 'ValuationTime', 'VWAPPrice', 'VWAPVE', 'VWAPVEExcludingClose', name='DeterminationMethodEnum'), nullable=False )
    valuationTimeType = Column(Enum('Close', 'Open', 'OSP', 'SpecificTime', 'XETRA', 'DerivativesClose', 'AsSpecifiedInMasterConfirmation', name='TimeTypeEnum'))
    DateRelativeToValuationDates_id = Column(Integer(), ForeignKey('DateRelativeToValuationDates.id'))
    valuationDates_id = Column(Integer(), ForeignKey('AdjustableRelativeOrPeriodicDates.id'))
    valuationDates = relationship("AdjustableRelativeOrPeriodicDates", uselist=False, foreign_keys=[valuationDates_id])
    valuationDate_id = Column(Integer(), ForeignKey('AdjustableOrRelativeDate.id'))
    valuationDate = relationship("AdjustableOrRelativeDate", uselist=False, foreign_keys=[valuationDate_id])
    valuationTime_id = Column(Integer(), ForeignKey('BusinessCenterTime.id'))
    valuationTime = relationship("BusinessCenterTime", uselist=False, foreign_keys=[valuationTime_id])
    

    def __repr__(self):
        return f"PerformanceValuationDates(id={self.id},determinationMethod={self.determinationMethod},valuationTimeType={self.valuationTimeType},DateRelativeToValuationDates_id={self.DateRelativeToValuationDates_id},valuationDates_id={self.valuationDates_id},valuationDate_id={self.valuationDate_id},valuationTime_id={self.valuationTime_id},)"



    


class FxRateSourceFixing(Base):
    """
    Describes a rate source to be fixed and the date the fixing occurs
    """
    __tablename__ = 'FxRateSourceFixing'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    settlementRateSource_id = Column(Integer(), ForeignKey('FxSettlementRateSource.id'), nullable=False )
    settlementRateSource = relationship("FxSettlementRateSource", uselist=False, foreign_keys=[settlementRateSource_id])
    fixingDate_id = Column(Integer(), ForeignKey('AdjustableDate.id'), nullable=False )
