class OffsetCalculation(Base):
    """
    Defines business day shifts for daily componded or averaged rates.  This type is used for lookback and lockout rates. This type is used to represent modular computed rates in interestRatePayouts.
    """
    __tablename__ = 'OffsetCalculation'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    offsetDays = Column(Integer())
    

    def __repr__(self):
        return f"OffsetCalculation(id={self.id},offsetDays={self.offsetDays},)"



    


class ObservationShiftCalculation(Base):
    """
    Parameters to describe the observation shift for a daily compounded or averaged floating rate. This type is used to represent modular computed rates in interestRatePayouts.
    """
    __tablename__ = 'ObservationShiftCalculation'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    offsetDays = Column(Integer())
    calculationBase = Column(Enum('SetInAdvance', 'Standard', 'FixingDate', name='ObservationPeriodDatesEnum'))
    additionalBusinessDays_id = Column(Integer(), ForeignKey('BusinessCenters.id'))
    additionalBusinessDays = relationship("BusinessCenters", uselist=False, foreign_keys=[additionalBusinessDays_id])
    

    def __repr__(self):
        return f"ObservationShiftCalculation(id={self.id},offsetDays={self.offsetDays},calculationBase={self.calculationBase},additionalBusinessDays_id={self.additionalBusinessDays_id},)"



    


class ObservationParameters(Base):
    """
    Parameters on daily observed computed rates, specifically daily caps and floors. This type is used to represent modular computed rates in interestRatePayouts.
    """
    __tablename__ = 'ObservationParameters'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    observationCapRate = Column(Numeric())
    observationFloorRate = Column(Numeric())
    

    def __repr__(self):
        return f"ObservationParameters(id={self.id},observationCapRate={self.observationCapRate},observationFloorRate={self.observationFloorRate},)"



    


class CalculatedRateDetails(Base):
    """
    Type for reporting details of calculated rates, including the observations that went into the final reported rate.
    """
    __tablename__ = 'CalculatedRateDetails'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    aggregateValue = Column(Numeric())
    aggregateWeight = Column(Numeric())
    calculatedRate = Column(Numeric())
    observations_id = Column(Integer(), ForeignKey('CalculatedRateObservations.id'))
    observations = relationship("CalculatedRateObservations", uselist=False, foreign_keys=[observations_id])
    
    
    weightedRates_rel = relationship( "CalculatedRateDetailsWeightedRates" )
    weightedRates = association_proxy("weightedRates_rel", "weightedRates",
                                  creator=lambda x_: CalculatedRateDetailsWeightedRates(weightedRates=x_))
    
    
    growthFactor_rel = relationship( "CalculatedRateDetailsGrowthFactor" )
    growthFactor = association_proxy("growthFactor_rel", "growthFactor",
                                  creator=lambda x_: CalculatedRateDetailsGrowthFactor(growthFactor=x_))
    
    
    compoundedGrowth_rel = relationship( "CalculatedRateDetailsCompoundedGrowth" )
    compoundedGrowth = association_proxy("compoundedGrowth_rel", "compoundedGrowth",
                                  creator=lambda x_: CalculatedRateDetailsCompoundedGrowth(compoundedGrowth=x_))
    

    def __repr__(self):
        return f"CalculatedRateDetails(id={self.id},aggregateValue={self.aggregateValue},aggregateWeight={self.aggregateWeight},calculatedRate={self.calculatedRate},observations_id={self.observations_id},)"



    


class CalculatedRateObservations(Base):
    """
    Type for reporting observations that went into the final reported rate.
    """
    __tablename__ = 'CalculatedRateObservations'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    
    
    observationDates_rel = relationship( "CalculatedRateObservationsObservationDates" )
    observationDates = association_proxy("observationDates_rel", "observationDates",
                                  creator=lambda x_: CalculatedRateObservationsObservationDates(observationDates=x_))
    
    
    weights_rel = relationship( "CalculatedRateObservationsWeights" )
    weights = association_proxy("weights_rel", "weights",
                                  creator=lambda x_: CalculatedRateObservationsWeights(weights=x_))
    
    
    observedRates_rel = relationship( "CalculatedRateObservationsObservedRates" )
    observedRates = association_proxy("observedRates_rel", "observedRates",
                                  creator=lambda x_: CalculatedRateObservationsObservedRates(observedRates=x_))
    
    
    processedRates_rel = relationship( "CalculatedRateObservationsProcessedRates" )
    processedRates = association_proxy("processedRates_rel", "processedRates",
                                  creator=lambda x_: CalculatedRateObservationsProcessedRates(processedRates=x_))
    

    def __repr__(self):
        return f"CalculatedRateObservations(id={self.id},)"



    


class CalculatedRateObservationDatesAndWeights(Base):
    """
    Type for reporting the observations dates and the corresponding weights going into a daily calculated rate
    """
    __tablename__ = 'CalculatedRateObservationDatesAndWeights'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    
    
    observationDates_rel = relationship( "CalculatedRateObservationDatesAndWeightsObservationDates" )
    observationDates = association_proxy("observationDates_rel", "observationDates",
                                  creator=lambda x_: CalculatedRateObservationDatesAndWeightsObservationDates(observationDates=x_))
    
    
    weights_rel = relationship( "CalculatedRateObservationDatesAndWeightsWeights" )
    weights = association_proxy("weights_rel", "weights",
                                  creator=lambda x_: CalculatedRateObservationDatesAndWeightsWeights(weights=x_))
    

    def __repr__(self):
        return f"CalculatedRateObservationDatesAndWeights(id={self.id},)"



    


class FloatingRateIndexDefinition(Base):
    """
    None
    """
    __tablename__ = 'FloatingRateIndexDefinition'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    definitionalSource = Column(Text())
    designatedMaturityApplicable = Column(Boolean())
    inLoan = Column(Boolean())
    deprecationReason = Column(Text())
    fpmlDescription = Column(Text())
    fro_id = Column(Integer(), ForeignKey('FloatingRateIndexIdentification.id'), nullable=False )
    fro = relationship("FloatingRateIndexIdentification", uselist=False, foreign_keys=[fro_id])
    calculationDefaults_id = Column(Integer(), ForeignKey('FloatingRateIndexCalculationDefaults.id'))
    calculationDefaults = relationship("FloatingRateIndexCalculationDefaults", uselist=False, foreign_keys=[calculationDefaults_id])
    mappings_id = Column(Integer(), ForeignKey('FloatingRateIndexMappings.id'))
    mappings = relationship("FloatingRateIndexMappings", uselist=False, foreign_keys=[mappings_id])
    externalMappings_id = Column(Integer(), ForeignKey('FloatingRateIndexExternalMappings.id'))
    externalMappings = relationship("FloatingRateIndexExternalMappings", uselist=False, foreign_keys=[externalMappings_id])
    history_id = Column(Integer(), ForeignKey('FroHistory.id'))
    history = relationship("FroHistory", uselist=False, foreign_keys=[history_id])
    
    
    # One-To-Many: OneToAnyMapping(source_class='FloatingRateIndexDefinition', source_slot='supportedDefinition', mapping_type=None, target_class='ContractualDefinition', target_slot='FloatingRateIndexDefinition_id', join_class=None, uses_join_table=None, multivalued=False)
    supportedDefinition = relationship( "ContractualDefinition", foreign_keys="[ContractualDefinition.FloatingRateIndexDefinition_id]")
    

    def __repr__(self):
        return f"FloatingRateIndexDefinition(id={self.id},definitionalSource={self.definitionalSource},designatedMaturityApplicable={self.designatedMaturityApplicable},inLoan={self.inLoan},deprecationReason={self.deprecationReason},fpmlDescription={self.fpmlDescription},fro_id={self.fro_id},calculationDefaults_id={self.calculationDefaults_id},mappings_id={self.mappings_id},externalMappings_id={self.externalMappings_id},history_id={self.history_id},)"



    


