class FloatingRateIndexCalculationDefaults(Base):
    """
    This holds the rate calculation defaults applicable for a floating rate index.
    """
    __tablename__ = 'FloatingRateIndexCalculationDefaults'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    category = Column(Enum('ScreenRate', 'Calculated', 'ReferenceBanks', name='FloatingRateIndexCategoryEnum'))
    indexStyle = Column(Enum('AverageFRO', 'CompoundedIndex', 'Index', 'Other', 'Overnight', 'PublishedAverage', 'SpecifiedFormula', 'SwapRate', 'TermRate', name='FloatingRateIndexStyleEnum'))
    method = Column(Enum('OISCompound', 'Average', 'Compounded', 'AllInCompounded', name='FloatingRateIndexCalculationMethodEnum'))
    dayCountFraction = Column(Enum('ACT_360', 'ACT_365L', 'ACT_364', 'ACT_365_FIXED', 'ACT_ACT_AFB', 'ACT_ACT_ICMA', 'ACT_ACT_ISDA', 'ACT_ACT_ISMA', 'CAL_252', '_1_1', '_30E_360', '_30E_360_ISDA', '_30_360', 'RBA_BOND_BASIS', name='DayCountFractionEnum'))
    publicationCalendar = Column(Text())
    applicableBusinessDays_id = Column(Integer(), ForeignKey('BusinessCenters.id'))
    applicableBusinessDays = relationship("BusinessCenters", uselist=False, foreign_keys=[applicableBusinessDays_id])
    
    
    # One-To-Many: OneToAnyMapping(source_class='FloatingRateIndexCalculationDefaults', source_slot='fixing', mapping_type=None, target_class='FloatingRateIndexFixingDetails', target_slot='FloatingRateIndexCalculationDefaults_id', join_class=None, uses_join_table=None, multivalued=False)
    fixing = relationship( "FloatingRateIndexFixingDetails", foreign_keys="[FloatingRateIndexFixingDetails.FloatingRateIndexCalculationDefaults_id]")
    

    def __repr__(self):
        return f"FloatingRateIndexCalculationDefaults(id={self.id},category={self.category},indexStyle={self.indexStyle},method={self.method},dayCountFraction={self.dayCountFraction},publicationCalendar={self.publicationCalendar},applicableBusinessDays_id={self.applicableBusinessDays_id},)"



    


