class FloatingRateIndexMap(Base):
    """
    A map for a single FRO to or from an equivalent or similar FRO in a different contractual definitions version.
    """
    __tablename__ = 'FloatingRateIndexMap'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    FloatingRateIndexMappings_id = Column(Integer(), ForeignKey('FloatingRateIndexMappings.id'))
    contractualDefinitionIdentifier_id = Column(Integer(), ForeignKey('ContractualDefinitionIdentifier.id'))
    contractualDefinitionIdentifier = relationship("ContractualDefinitionIdentifier", uselist=False, foreign_keys=[contractualDefinitionIdentifier_id])
    identifier_id = Column(Integer(), ForeignKey('Identifier.id'))
    identifier = relationship("Identifier", uselist=False, foreign_keys=[identifier_id])
    
    
    index__rel = relationship( "FloatingRateIndexMapIndex" )
    index_ = association_proxy("index__rel", "index_",
                                  creator=lambda x_: FloatingRateIndexMapIndex(index_=x_))
    

    def __repr__(self):
        return f"FloatingRateIndexMap(id={self.id},FloatingRateIndexMappings_id={self.FloatingRateIndexMappings_id},contractualDefinitionIdentifier_id={self.contractualDefinitionIdentifier_id},identifier_id={self.identifier_id},)"



    


