class Trigger(Base):
    """
    Trigger point at which feature is effective.
    """
    __tablename__ = 'Trigger'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    triggerType = Column(Enum('EqualOrLess', 'EqualOrGreater', 'Equal', 'Less', 'Greater', name='TriggerTypeEnum'))
    triggerTimeType = Column(Enum('Closing', 'Anytime', name='TriggerTimeTypeEnum'))
    creditEvents_id = Column(Integer(), ForeignKey('CreditEvents.id'))
    creditEvents = relationship("CreditEvents", uselist=False, foreign_keys=[creditEvents_id])
    creditEventsReference_id = Column(Integer(), ForeignKey('CreditEvents.id'))
    creditEventsReference = relationship("CreditEvents", uselist=False, foreign_keys=[creditEventsReference_id])
    
    
    # One-To-Many: OneToAnyMapping(source_class='Trigger', source_slot='level', mapping_type=None, target_class='PriceSchedule', target_slot='Trigger_id', join_class=None, uses_join_table=None, multivalued=False)
