class StubValue(Base):
    """
    A type defining how a stub calculation period amount is calculated. A single floating rate tenor different to that used for the regular part of the calculation periods schedule may be specified, or two floating rate tenors many be specified. If two floating rate tenors are specified then Linear Interpolation (in accordance with the 2000 ISDA Definitions, Section 8.3 Interpolation) is assumed to apply. Alternatively, an actual known stub rate or stub amount may be specified.
    """
    __tablename__ = 'StubValue'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    stubRate = Column(Numeric())
    stubAmount_id = Column(Integer(), ForeignKey('Money.id'))
    stubAmount = relationship("Money", uselist=False, foreign_keys=[stubAmount_id])
    
    
    # One-To-Many: OneToAnyMapping(source_class='StubValue', source_slot='floatingRate', mapping_type=None, target_class='StubFloatingRate', target_slot='StubValue_id', join_class=None, uses_join_table=None, multivalued=False)
    floatingRate = relationship( "StubFloatingRate", foreign_keys="[StubFloatingRate.StubValue_id]")
    

    def __repr__(self):
        return f"StubValue(id={self.id},stubRate={self.stubRate},stubAmount_id={self.stubAmount_id},)"



    


class FixedAmountCalculationDetails(Base):
    """
    Type for reporting the detailed results of calculating a cash flow for a calculation period.  This is enhanced relative to the FpML-based cashflows structure to allow more information to be returned about daily compounded rates.
    """
    __tablename__ = 'FixedAmountCalculationDetails'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    fixedRate = Column(Numeric(), nullable=False )
    yearFraction = Column(Numeric(), nullable=False )
    calculatedAmount = Column(Numeric(), nullable=False )
    calculationPeriod_id = Column(Integer(), ForeignKey('CalculationPeriodBase.id'), nullable=False )
    calculationPeriod = relationship("CalculationPeriodBase", uselist=False, foreign_keys=[calculationPeriod_id])
    calculationPeriodNotionalAmount_id = Column(Integer(), ForeignKey('Money.id'), nullable=False )
    calculationPeriodNotionalAmount = relationship("Money", uselist=False, foreign_keys=[calculationPeriodNotionalAmount_id])
    

    def __repr__(self):
        return f"FixedAmountCalculationDetails(id={self.id},fixedRate={self.fixedRate},yearFraction={self.yearFraction},calculatedAmount={self.calculatedAmount},calculationPeriod_id={self.calculationPeriod_id},calculationPeriodNotionalAmount_id={self.calculationPeriodNotionalAmount_id},)"



    


