class StubPeriod(Base):
    """
     A class defining how the initial or final stub calculation period amounts is calculated. For example, the rate to be applied to the initial or final stub calculation period may be the linear interpolation of two different tenors for the floating rate index specified in the calculation period amount component, e.g. A two month stub period may used the linear interpolation of a one month and three month floating rate. The different rate tenors would be specified in this component. Note that a maximum of two rate tenors can be specified. If a stub period uses a single index tenor and this is the same as that specified in the calculation period amount component then the initial stub or final stub component, as the case may be, must not be included.
    """
    __tablename__ = 'StubPeriod'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    calculationPeriodDatesReference_id = Column(Integer(), ForeignKey('CalculationPeriodDates.id'), nullable=False )
    calculationPeriodDatesReference = relationship("CalculationPeriodDates", uselist=False, foreign_keys=[calculationPeriodDatesReference_id])
    initialStub_id = Column(Integer(), ForeignKey('StubValue.id'))
    initialStub = relationship("StubValue", uselist=False, foreign_keys=[initialStub_id])
    finalStub_id = Column(Integer(), ForeignKey('StubValue.id'))
    finalStub = relationship("StubValue", uselist=False, foreign_keys=[finalStub_id])
    

    def __repr__(self):
        return f"StubPeriod(id={self.id},calculationPeriodDatesReference_id={self.calculationPeriodDatesReference_id},initialStub_id={self.initialStub_id},finalStub_id={self.finalStub_id},)"



    


class CalculationPeriodBase(Base):
    """
    The calculation period adjusted start and end dates, which are the baseline arguments needed to compute an interest accrual calculation.
    """
    __tablename__ = 'CalculationPeriodBase'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    adjustedStartDate = Column(Date())
    adjustedEndDate = Column(Date())
    

    def __repr__(self):
        return f"CalculationPeriodBase(id={self.id},adjustedStartDate={self.adjustedStartDate},adjustedEndDate={self.adjustedEndDate},)"



    


class CalculationPeriodDates(Base):
    """
    A data for:  defining the parameters used to generate the calculation period dates schedule, including the specification of any initial or final stub calculation periods. A calculation period schedule consists of an optional initial stub calculation period, one or more regular calculation periods and an optional final stub calculation period. In the absence of any initial or final stub calculation periods, the regular part of the calculation period schedule is assumed to be between the effective date and the termination date. No implicit stubs are allowed, i.e. stubs must be explicitly specified using an appropriate combination of firstPeriodStartDate, firstRegularPeriodStartDate and lastRegularPeriodEndDate.
    """
    __tablename__ = 'CalculationPeriodDates'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    firstRegularPeriodStartDate = Column(Date())
    firstCompoundingPeriodEndDate = Column(Date())
    lastRegularPeriodEndDate = Column(Date())
    effectiveDate_id = Column(Integer(), ForeignKey('AdjustableOrRelativeDate.id'))
    effectiveDate = relationship("AdjustableOrRelativeDate", uselist=False, foreign_keys=[effectiveDate_id])
    terminationDate_id = Column(Integer(), ForeignKey('AdjustableOrRelativeDate.id'))
    terminationDate = relationship("AdjustableOrRelativeDate", uselist=False, foreign_keys=[terminationDate_id])
    calculationPeriodDatesAdjustments_id = Column(Integer(), ForeignKey('BusinessDayAdjustments.id'))
    calculationPeriodDatesAdjustments = relationship("BusinessDayAdjustments", uselist=False, foreign_keys=[calculationPeriodDatesAdjustments_id])
    firstPeriodStartDate_id = Column(Integer(), ForeignKey('AdjustableOrRelativeDate.id'))
    firstPeriodStartDate = relationship("AdjustableOrRelativeDate", uselist=False, foreign_keys=[firstPeriodStartDate_id])
    calculationPeriodFrequency_id = Column(Integer(), ForeignKey('CalculationPeriodFrequency.id'))
    calculationPeriodFrequency = relationship("CalculationPeriodFrequency", uselist=False, foreign_keys=[calculationPeriodFrequency_id])
    
    
    stubPeriodType_rel = relationship( "CalculationPeriodDatesStubPeriodType" )
    stubPeriodType = association_proxy("stubPeriodType_rel", "stubPeriodType",
                                  creator=lambda x_: CalculationPeriodDatesStubPeriodType(stubPeriodType=x_))
    

    def __repr__(self):
        return f"CalculationPeriodDates(id={self.id},firstRegularPeriodStartDate={self.firstRegularPeriodStartDate},firstCompoundingPeriodEndDate={self.firstCompoundingPeriodEndDate},lastRegularPeriodEndDate={self.lastRegularPeriodEndDate},effectiveDate_id={self.effectiveDate_id},terminationDate_id={self.terminationDate_id},calculationPeriodDatesAdjustments_id={self.calculationPeriodDatesAdjustments_id},firstPeriodStartDate_id={self.firstPeriodStartDate_id},calculationPeriodFrequency_id={self.calculationPeriodFrequency_id},)"



    


