class ResolvablePriceQuantity(Base):
    """
    Generic class to specify the quantity for different payout legs in a contractual product, when that quantity can vary across payout legs or across time. A resolvable quantity can always be resolved into a single quantity from the quantity notation which has a corresponding asset identifier. In addition to the base case, where quantity is directly specified as a number as part of the quantity notation, the other use cases are: (i) quantity based on some pre-defined schedule (eg amortising notional), (ii) quantity based on some pre-defined events (eg resetting cross-currency notional), or quantity set as reference to another quantity (eg equity notional as no. securities x price).
    """
    __tablename__ = 'ResolvablePriceQuantity'

    id = Column(Integer(), primary_key=True, autoincrement=True , nullable=False )
    reset = Column(Boolean())
    resolvedQuantity_id = Column(Integer(), ForeignKey('Quantity.id'))
    resolvedQuantity = relationship("Quantity", uselist=False, foreign_keys=[resolvedQuantity_id])
    quantitySchedule_id = Column(Integer(), ForeignKey('NonNegativeQuantitySchedule.id'))
    quantitySchedule = relationship("NonNegativeQuantitySchedule", uselist=False, foreign_keys=[quantitySchedule_id])
    quantityReference_id = Column(Integer(), ForeignKey('ResolvablePriceQuantity.id'))
    quantityReference = relationship("ResolvablePriceQuantity", uselist=False, foreign_keys=[quantityReference_id])
    quantityMultiplier_id = Column(Integer(), ForeignKey('QuantityMultiplier.id'))
    quantityMultiplier = relationship("QuantityMultiplier", uselist=False, foreign_keys=[quantityMultiplier_id])
    futureValueNotional_id = Column(Integer(), ForeignKey('FutureValueAmount.id'))
    futureValueNotional = relationship("FutureValueAmount", uselist=False, foreign_keys=[futureValueNotional_id])
    
    
    # One-To-Many: OneToAnyMapping(source_class='ResolvablePriceQuantity', source_slot='priceSchedule', mapping_type=None, target_class='PriceSchedule', target_slot='ResolvablePriceQuantity_id', join_class=None, uses_join_table=None, multivalued=False)
    priceSchedule = relationship( "PriceSchedule", foreign_keys="[PriceSchedule.ResolvablePriceQuantity_id]")
    

    def __repr__(self):
        return f"ResolvablePriceQuantity(id={self.id},reset={self.reset},resolvedQuantity_id={self.resolvedQuantity_id},quantitySchedule_id={self.quantitySchedule_id},quantityReference_id={self.quantityReference_id},quantityMultiplier_id={self.quantityMultiplier_id},futureValueNotional_id={self.futureValueNotional_id},)"



    


