    valuationDate_id = Column(Integer(), ForeignKey('ValuationDate.id'))
    valuationDate = relationship("ValuationDate", uselist=False, foreign_keys=[valuationDate_id])
    valuationTime_id = Column(Integer(), ForeignKey('BusinessCenterTime.id'))
    valuationTime = relationship("BusinessCenterTime", uselist=False, foreign_keys=[valuationTime_id])
    cashSettlementAmount_id = Column(Integer(), ForeignKey('Money.id'))
    cashSettlementAmount = relationship("Money", uselist=False, foreign_keys=[cashSettlementAmount_id])
    

    def __repr__(self):
        return f"CashSettlementTerms(id={self.id},cashSettlementMethod={self.cashSettlementMethod},recoveryFactor={self.recoveryFactor},fixedSettlement={self.fixedSettlement},accruedInterest={self.accruedInterest},SettlementTerms_id={self.SettlementTerms_id},valuationMethod_id={self.valuationMethod_id},valuationDate_id={self.valuationDate_id},valuationTime_id={self.valuationTime_id},cashSettlementAmount_id={self.cashSettlementAmount_id},)"



    


